async function GetVendorOwnerlist(instance,modulename, filtername) {
    var vm = instance;
    let params= `id=&moduleName=${modulename}&type=${filtername}&search=&refId=`
   await VendorDataService.GetDDLData(params)
        .then(function (response) {
        var json = response.data;            
            if (json != null) {        
                vm.leftSearchFields[2].listOptions = json.DATA;
                vm.VendorOwnerList = json.DATA;   
                return vm.VendorOwnerList;               
            }
        });
}

export default { buttons, leftSearchFields ,listActions,GetVendorOwnerlist};